    let tcp_ack = build_tcp_ack(40080, 80);
    let ip_hdr = match build_ip_header(6, &bottle_ip, &dst_ip, tcp_ack.len()) {
        Ok(h) => h,
        Err(e) => return fail(format!("ERROR: build IP header: {}", e)),
    };
